import lombok.RequiredArgsConstructor;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

@Service
@RequiredArgsConstructor
public class AuthService {

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final AuthenticationManager authenticationManager;
    private final JwtService jwtService;

    public String register(RegisterRequest request) {
        String encodedPassword = passwordEncoder.encode(request.getPassword());

        User user = User.builder()
                .email(request.getEmail())
                .password(encodedPassword)
                .role(Role.USER)
                .build();

        userRepository.save(user);
        return "Kullanıcı başarıyla kaydedildi.";
    }

    public AuthResponse login(LoginRequest request) {
        UsernamePasswordAuthenticationToken authToken =
            new UsernamePasswordAuthenticationToken(request.getEmail(), request.getPassword());

        Authentication auth = authenticationManager.authenticate(authToken);
        String token = jwtService.generateToken(auth.getName());

        return new AuthResponse(token, "Giriş başarılı");
    }
}

questions.answerBody:
Kayıt (Register) ve Giriş (Login) işlemlerini içeren, Spring Security standartlarına uygun `AuthService` yapısı aşağıdadır. Bu yapıda şifrelerin güvenliği için `PasswordEncoder`, doğrulama için ise `AuthenticationManager` kullanılır.

### AuthService Uygulaması

```java
import lombok.RequiredArgsConstructor;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

@Service
@RequiredArgsConstructor // Constructor injection için (Lombok)
public class AuthService {

    private final UserRepository userRepository;
    private final PasswordEncoder passwordEncoder;
    private final AuthenticationManager authenticationManager;
    private final JwtService jwtService; // Token üretmek için varsayımsal servis

    /**
     * Yeni kullanıcı kaydı: Şifre mutlaka encode edilerek DB'ye yazılır.
     */
    public String register(RegisterRequest request) {
        // 1. Şifreyi BCrypt (veya tanımlı encoder) ile hashle
        String encodedPassword = passwordEncoder.encode(request.getPassword());

        // 2. Kullanıcı nesnesini oluştur ve kaydet
        User user = User.builder()
                .email(request.getEmail())
                .password(encodedPassword) // Hashlenmiş şifre!
                .role(Role.USER)
                .build();

        userRepository.save(user);
        return "Kullanıcı başarıyla kaydedildi.";
    }

    /**
     * Giriş işlemi: AuthenticationManager ile doğrulama yapılır.
     */
    public AuthResponse login(LoginRequest request) {
        // 1. Kimlik bilgilerini bir "zarfa" koy (Henüz doğrulanmadı)
        UsernamePasswordAuthenticationToken authToken =
            new UsernamePasswordAuthenticationToken(request.getEmail(), request.getPassword());

        // 2. Manager'a ver ve doğrula (Hatalı şifrede BadCredentialsException fırlatır)
        Authentication auth = authenticationManager.authenticate(authToken);

        // 3. Buraya gelindiyse doğrulama başarılıdır.
        // JWT üret ve response olarak dön.
        String token = jwtService.generateToken(auth.getName());

        return new AuthResponse(token, "Giriş başarılı");
    }
}
```

---

### Bu Akışta Neler Oluyor?

**1. Register (Kayıt) Kısmı:**
* **`passwordEncoder.encode()`**: Daha önce konuştuğumuz gibi, kullanıcının girdiği `"secret"` metnini alır ve `$2a$10$...` şeklinde bir hash'e dönüştürür. Veritabanına asla ham şifre girmez.

**2. Login (Giriş) Kısmı:**
* **`authenticationManager.authenticate()`**: Bu metodu çağırdığında Spring Security otomatik olarak senin `UserDetailsService`'ine gider, kullanıcıyı bulur ve `PasswordEncoder.matches()` ile şifreyi kıyaslar.
* **Hata Yönetimi**: Eğer şifre yanlışsa kodun geri kalanı çalışmaz, Spring bir **Exception** fırlatır. Bu yüzden `if (passwordCorrect)` gibi manuel kontrollere gerek kalmaz.

**3. Başarılı Sonuç:**
* Doğrulama geçtikten sonra bir **JWT** üretilir. Bu JWT artık kullanıcının sonraki isteklerdeki "pasaportu" olacaktır.

